DDL:
DROP TABLE IF EXISTS DIM_GEOGRAPHY CASCADE;
CREATE TABLE DIM_GEOGRAPHY (
	GEOGRAPHY_ID BIGINT PRIMARY KEY,
	COUNTRY VARCHAR(20),
	STATE VARCHAR(100),
	DISTRICT VARCHAR(50),
	SUB_DISTRICT VARCHAR(100),
	TYPE_OF_AREA VARCHAR(20)
);

DROP TABLE IF EXISTS DIM_TIME CASCADE;
CREATE TABLE DIM_TIME (
	TIME_ID BIGINT PRIMARY KEY,
	YEAR INTEGER,
	MONTH VARCHAR(30)
);

DROP TABLE IF EXISTS FACT_OUTPATIENT_SERVICES CASCADE;
CREATE TABLE FACT_OUTPATIENT_SERVICES (
	OUTPATIENT_ID BIGINT PRIMARY KEY,
	GEOGRAPHY_ID BIGINT,
	TIME_ID BIGINT,
	OUTPATIENT_ATTENDANCE_ALLOPATHIC DOUBLE PRECISION,
	FOREIGN KEY (GEOGRAPHY_ID) REFERENCES DIM_GEOGRAPHY (GEOGRAPHY_ID),
	FOREIGN KEY (TIME_ID) REFERENCES DIM_TIME (TIME_ID)
);
